plan.raw_text:
{
  "goal": "为用户推荐一个详细的北京3天旅游计划，包含甜食体验和有历史底蕴的景点",
  "graph_policy": {
    "max_parallelism": 1,
    "fail_fast": true
  },
  "steps": [
    {
      "title": "收集用户偏好与约束",
      "instruction": "整理用户已提供的偏好信息，包括喜欢甜食、尤其是蛋糕，以及对有历史底蕴景点的兴趣。",
      "depends_on": [],
      "input_bindings": []
    },
    {
      "title": "规划历史景点行程",
      "instruction": "根据用户偏好，推荐3个有历史底蕴的景点，并规划每天的行程安排。",
      "depends_on": ["S1"],
      "input_bindings": [
        {"from": "S1.output_text", "to": "preferences"}
      ]
    },
    {
      "title": "推荐甜食体验",
      "instruction": "根据用户对甜食的偏好，推荐3家以蛋糕闻名的甜品店或餐厅，并标注位置和特色。",
      "depends_on": ["S1"],
      "input_bindings": [
        {"from": "S1.output_text", "to": "preferences"}
      ]
    },
    {
      "title": "整合行程与预算",
      "instruction": "将历史景点行程和甜食体验整合，形成完整的3天旅游计划，并估算总预算。",
      "depends_on": ["S2", "S3"],
      "input_bindings": [
        {"from": "S2.output_text", "to": "historical_itinerary"},
        {"from": "S3.output_text", "to": "sweet_spot_recommendations"}
      ]
    }
  ]
}
